import{_ as e,o as d,c as o,ag as i}from"./chunks/framework.HG0H2VLS.js";const h=JSON.parse('{"title":"TimePicker — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/components/TimePicker/TimePicker.figma-notes.md","filePath":"public/demos/src/components/TimePicker/TimePicker.figma-notes.md"}'),a={name:"public/demos/src/components/TimePicker/TimePicker.figma-notes.md"};function r(n,t,c,s,l,p){return d(),o("div",null,[...t[0]||(t[0]=[i('<h1 id="timepicker-—-figma-notes" tabindex="-1">TimePicker — Figma Notes <a class="header-anchor" href="#timepicker-—-figma-notes" aria-label="Permalink to &quot;TimePicker — Figma Notes&quot;">​</a></h1><p><strong>Figma URL:</strong> <a href="https://www.figma.com/design/Lus07xi8pPXLN87sQIyrEt/Affino-AI---Design-System?node-id=2522-1532" target="_blank" rel="noreferrer">node 2522:1532</a></p><h2 id="component-set" tabindex="-1">Component Set <a class="header-anchor" href="#component-set" aria-label="Permalink to &quot;Component Set&quot;">​</a></h2><p>TimePicker is a Tier=Component design-system component for time entry. The set bundles six related compositions sharing the same field styling — single input, segmented input + dropdown, range, range with reveal, and a grid of pre-set slots.</p><h2 id="variant-matrix" tabindex="-1">Variant Matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant Matrix&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Node</th><th>Type</th><th>Notes</th></tr></thead><tbody><tr><td><code>2522:1529</code></td><td>Single input</td><td>Label + clock icon + time text. Width <code>--ai-size-1</code> (128px)</td></tr><tr><td><code>2522:1530</code></td><td>Duration</td><td>Time field + duration dropdown segmented. Width <code>--ai-size-3</code> (192px)</td></tr><tr><td><code>2522:1531</code></td><td>Timezone</td><td>Time field + timezone dropdown with globe icon. Width <code>--ai-size-5</code> (280px)</td></tr><tr><td><code>2522:1527</code></td><td>Range</td><td>Two single inputs side-by-side (Start / End)</td></tr><tr><td><code>2522:1528</code></td><td>Range Reveal</td><td>Single input with &quot;+ Add end time&quot; button that reveals the second</td></tr><tr><td><code>2522:1526</code></td><td>Slots</td><td>4×3 grid of selectable time pills with selected and disabled states</td></tr></tbody></table><h2 id="css-class-mapping" tabindex="-1">CSS Class Mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS Class Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma property</th><th>CSS class</th></tr></thead><tbody><tr><td>Type=Single input</td><td><code>.tp.tp--single</code></td></tr><tr><td>Type=Duration</td><td><code>.tp.tp--segmented.tp--duration</code></td></tr><tr><td>Type=Timezone</td><td><code>.tp.tp--segmented.tp--timezone</code></td></tr><tr><td>Type=Range</td><td><code>.tp-range</code> (wraps two <code>.tp</code> fields)</td></tr><tr><td>Type=Range Reveal</td><td><code>.tp-reveal</code> (with <code>.tp-reveal--open</code> after JS toggle)</td></tr><tr><td>Type=Slots</td><td><code>.tp-slots</code> (radio group of <code>.tp-slot</code>)</td></tr><tr><td>Slot selected</td><td><code>.tp-slot__input:checked</code> styles label</td></tr><tr><td>Slot disabled</td><td><code>.tp-slot__input:disabled</code> styles label</td></tr></tbody></table><h2 id="token-mapping" tabindex="-1">Token Mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token Mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Value</th></tr></thead><tbody><tr><td>Field bg</td><td><code>--ai-surface-primary</code></td><td>#ffffff</td></tr><tr><td>Field border</td><td><code>--ai-border-secondary</code></td><td>#e2e2e3</td></tr><tr><td>Field radius</td><td><code>--ai-radius-md</code></td><td>8px</td></tr><tr><td>Field height</td><td><code>--ai-spacing-8</code></td><td>40px</td></tr><tr><td>Field padding</td><td><code>--ai-spacing-5</code> (16px horizontal)</td><td></td></tr><tr><td>Label gap</td><td><code>--ai-spacing-3</code></td><td>8px</td></tr><tr><td>Label font</td><td><code>--ai-font-title</code> semibold + <code>--ai-font-fixed-xs</code></td><td>Inter 600 / 14px</td></tr><tr><td>Time text font</td><td><code>--ai-font-title</code> regular + <code>--ai-font-fixed-xs</code></td><td>Inter 400 / 14px</td></tr><tr><td>Time text color</td><td><code>--ai-text-primary</code></td><td>#212123</td></tr><tr><td>Icon size</td><td><code>--ai-icon-size-sm</code></td><td>16px</td></tr><tr><td>Icon color</td><td><code>--ai-icon-contrast</code></td><td>#929295</td></tr><tr><td>Single input width</td><td><code>--ai-size-1</code></td><td>128px</td></tr><tr><td>Duration width</td><td><code>--ai-size-3</code></td><td>192px</td></tr><tr><td>Timezone width</td><td><code>--ai-size-5</code></td><td>280px</td></tr><tr><td>Dropdown bg</td><td><code>--ai-surface-minimal</code></td><td>#f6f6f7</td></tr><tr><td>Dropdown hover bg</td><td><code>--ai-surface-secondary</code></td><td>#e2e2e3</td></tr><tr><td>Dropdown text</td><td><code>--ai-font-medium</code> + <code>--ai-font-fixed-xs</code></td><td>Inter 500 / 14px</td></tr><tr><td>Dropdown padding</td><td><code>--ai-spacing-4</code> (12px horizontal)</td><td></td></tr><tr><td>Dropdown gap</td><td><code>--ai-spacing-2</code></td><td>6px</td></tr><tr><td>Range gap</td><td><code>--ai-spacing-5</code></td><td>16px</td></tr><tr><td>Reveal &quot;+&quot; button color</td><td><code>--ai-surface-brand</code></td><td>#0071d8</td></tr><tr><td>Slot label font</td><td><code>--ai-font-medium</code> + <code>--ai-font-fixed-xs</code></td><td>Inter 500 / 14px</td></tr><tr><td>Slot label padding</td><td><code>--ai-spacing-4</code> (12px horizontal)</td><td></td></tr><tr><td>Slot grid gap</td><td><code>--ai-spacing-3</code></td><td>8px</td></tr><tr><td>Slot selected bg</td><td><code>--ai-surface-brand</code></td><td>#0071d8</td></tr><tr><td>Slot selected text</td><td><code>--ai-btn-primary-text</code></td><td>#ffffff</td></tr><tr><td>Slot disabled bg</td><td><code>--ai-surface-minimal</code></td><td>#f6f6f7</td></tr><tr><td>Slot disabled text</td><td><code>--ai-text-contrast</code></td><td>#67676c</td></tr><tr><td>Focus ring</td><td><code>--ai-surface-brand-contrast</code></td><td>brand contrast</td></tr></tbody></table><h2 id="token-gaps" tabindex="-1">Token Gaps <a class="header-anchor" href="#token-gaps" aria-label="Permalink to &quot;Token Gaps&quot;">​</a></h2><p>None. The <code>1px</code> and <code>2px</code> raw values used internally are border widths / inner padding offsets — optical units per CLAUDE rules, not token gaps.</p><h2 id="icons" tabindex="-1">Icons <a class="header-anchor" href="#icons" aria-label="Permalink to &quot;Icons&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Element</th><th>Lucide name</th></tr></thead><tbody><tr><td>Time field leading icon</td><td><code>clock</code></td></tr><tr><td>Dropdown chevron</td><td><code>chevron-down</code></td></tr><tr><td>Timezone leading icon</td><td><code>globe</code></td></tr><tr><td>Reveal add button</td><td><code>plus</code></td></tr></tbody></table><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><p>None — TimePicker is self-contained. The time text is rendered as <code>&lt;input type=&quot;text&quot;&gt;</code> rather than <code>&lt;input type=&quot;time&quot;&gt;</code> because native time inputs do not display their value as plain text in some Figma capture flows; using <code>type=&quot;text&quot;</code> keeps the time string visible while still allowing free-text entry.</p><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li>Figma&#39;s variable defs API reports <code>--ai-text-error</code> as <code>#0071d8</code> (the brand blue), but the generated CSS has <code>#ef4444</code>. The token isn&#39;t used by TimePicker so it doesn&#39;t affect this build, but worth flagging for the next Figma token sync.</li><li>All time inputs use <code>&lt;input type=&quot;text&quot;&gt;</code> for Figma-capture fidelity. Production wiring may swap to native <code>&lt;input type=&quot;time&quot;&gt;</code> if interaction precision matters more than visual fidelity.</li><li>The grid in Type=Slots is positioned absolutely in Figma but expressed with CSS Grid (<code>repeat(4, 1fr)</code>) in code — same visual outcome, more flexible for variable column counts.</li></ul>',18)])])}const u=e(a,[["render",r]]);export{h as __pageData,u as default};
